import json
import sqlite3
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]


def sql(name):
    return (ROOT / "sql" / name).read_text()


def database():
    db = sqlite3.connect(":memory:")
    db.executescript("""
        CREATE TABLE document (document_id INTEGER PRIMARY KEY, title TEXT, required_role TEXT);
        CREATE TABLE principal_grant (principal_id TEXT PRIMARY KEY, roles_json TEXT NOT NULL CHECK (json_valid(roles_json)));
        CREATE TABLE role_audit (principal_id TEXT, role_code TEXT, action TEXT);
    """)
    return db


def test_exact_role_selection_deletion_and_audit():
    db = database()
    db.executemany("INSERT INTO document VALUES (?, ?, ?)", [
        (1, "Public", None), (2, "Guide", "reader"), (3, "Admin", "admin")
    ])
    rows = db.execute(sql("select_authorized_documents.sql"), {"roles_json": json.dumps(["reader"])}).fetchall()
    assert rows == [(1, "Public"), (2, "Guide")]

    db.execute("INSERT INTO principal_grant VALUES (?, ?)", ("p1", json.dumps(["reader"])))
    db.execute(sql("delete_role_grant.sql"), {"principal_id": "p1", "role": "reader"})
    assert json.loads(db.execute("SELECT roles_json FROM principal_grant").fetchone()[0]) == []

    db.execute(sql("audit_role_change.sql"), {"principal_id": "p1", "role": "reader", "action": "removed"})
    assert db.execute("SELECT * FROM role_audit").fetchone() == ("p1", "reader", "removed")
